1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
20	type Step = { op: "quote"; items: Item[] };
21	type Scenario = { customer: unknown; steps: Step[] };
22	
23	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const groupByType = (items: Item[]): Map<string, number> =>
28	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
29	
30	const componentGroupPremium = (type: string, count: number): number =>
31	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
32	
33	const componentsPremium = (items: Item[]): number =>
34	  Array.from(groupByType(items.filter(isComponent)))
35	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
36	
37	const itemSurcharge = (item: Item): number =>
38	  (item.cursed ? CURSED_SURCHARGE : 0) +
39	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE : 0);
40	
41	const itemPremium = (item: Item): number =>
42	  basePremiumFor(item.type) * (1 + itemSurcharge(item));
43	
44	const mainItemsPremium = (items: Item[]): number =>
45	  items.filter((item) => !isComponent(item))
46	    .reduce((sum, item) => sum + itemPremium(item), 0);
47	
48	const itemsPremium = (items: Item[]): number =>
49	  mainItemsPremium(items) + componentsPremium(items);
50	
51	const quote = ({ items }: Step): { premium: number } => ({
52	  premium: itemsPremium(items) + PROCESSING_FEE,
53	});
54	
55	export const runScenario = (input: unknown): unknown => {
56	  const { steps } = input as Scenario;
57	  return { results: steps.map(quote) };
58	};
